"""
MKT Christ Commentary — Isaiah chapter 57
Run: python3 scripts/zc-christ-isaiah-57.py

Isaiah 57 divides into three sections:
1. vv.1-2: The death of the righteous unnoticed — lament over martyrdom
2. vv.3-13: Oracle against the idolaters — adultery imagery, high places, futile alliances
3. vv.14-21: The oracle of comfort — YHWH dwelling with the contrite; peace
   proclaimed near and far; the wicked like a tossing sea

Key Christological texts:
- 57:15: "high and lifted up... dwells with the contrite" → John 12:41; John 14:23;
  Matt 5:3 (the infinite condescension of incarnation)
- 57:19: "peace to the far and to the near" → Eph 2:17 (Paul's direct application
  to Gentile/Jew inclusion in Christ)
- 57:14: "prepare the way" → Matt 3:3 (John the Baptist)
- 57:20-21: the wicked like tossing sea → Mark 4:39; Rev 21:1
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "57": {
    "1": '<p>"The righteous man perishes, and no one takes it to heart; devout men are taken away, while no one understands. For the righteous man is taken away from calamity." The death of the righteous going unnoticed — the injustice of the world\'s indifference to martyrdom. Matt 5:10-12: "Blessed are those who are persecuted for righteousness\' sake, for theirs is the kingdom of heaven." Heb 11:37-38: "They were stoned, they were sawn in two, they were killed with the sword... of whom the world was not worthy." Rev 6:9-11: the souls under the altar — those slain "for the word of God and for the witness they had borne" — are the righteous of Isaiah 57:1 who perished without the world taking notice. Christ\'s own death was officially noted only as a criminal\'s execution (Matt 27:37 — the charge posted above the cross); the world did not recognize that the Righteous One was dying for their calamity.</p>',
    "2": '<p>"He enters into peace; they rest in their beds who walk in their uprightness." The rest of the righteous dead — "entering into peace." John 11:11: "Our friend Lazarus has fallen asleep, but I go to awaken him" — Jesus uses the sleep metaphor for death that 57:2 inaugurates. 1 Thess 4:13-14: "we do not want you to be uninformed, brothers, about those who are asleep, that you may not grieve as others do who have no hope. For since we believe that Jesus died and rose again, even so, through Jesus, God will bring with him those who have fallen asleep." The bed-rest of the righteous dead in Isaiah 57:2 is the sleep-in-Christ of 1 Thessalonians — not final unconsciousness but guarded rest awaiting the resurrection. Rev 14:13: "Blessed are the dead who die in the Lord from now on... they will rest from their labors."</p>',
    "3": '<p>"But you, draw near, sons of the sorceress, offspring of the adulterer and the loose woman." The sharp address to the opposing community — the idolaters. Matt 3:7: "You brood of vipers!" (John the Baptist to the Pharisees and Sadducees). John 8:41,44: "You do the works of your father... you are of your father the devil, and your will is to do your father\'s desires." The "sons of the sorceress" language denotes those who belong to the anti-community through spiritual adultery — the worship of other powers. Rev 17:5: "Babylon the great, mother of prostitutes and of earth\'s abominations." The NT continues the OT use of adultery/sorcery language for religious unfaithfulness, with Jesus and John both identifying the established religious leadership as the "offspring" of the adversary.</p>',
    "4": '<p>"Whom are you mocking? Against whom do you open your mouth wide and stick out your tongue? Are you not children of transgression, the offspring of deceit?" The mockers who open their mouths wide. Matt 27:39: "those who passed by derided him, wagging their heads." Ps 22:7 (the messianic psalm): "all who see me mock me; they make mouths at me; they wag their heads." Luke 23:35-39: rulers, soldiers, and one of the criminals all mock the crucified Jesus — the wide-mouthed contempt of Isaiah 57:4 enacted at Calvary. Ps 35:21 ("they open wide their mouths against me") and Lam 2:16 use the same imagery. The children of transgression mocking the Righteous One is the pattern that reaches its extreme expression at the cross, where the cosmic mocking of the suffering Servant occurs.</p>',
    "5": '<p>"You who burn with lust among the oaks, under every green tree, who slaughter your children in the valleys, under the clefts of the rocks." The child sacrifices and tree-worship of Canaanite syncretism — the extreme apostasy of covenant betrayal. Matt 23:35: "so that on you may come all the righteous blood shed on earth, from the blood of righteous Abel to the blood of Zechariah." Rev 18:24: "in her was found the blood of prophets and of saints, and of all who have been slain on earth." The slaughter of children as idol-sacrifice is the darkest point of the OT\'s spiritual adultery — the extreme to which false worship leads. John 8:44: the devil "was a murderer from the beginning" — the child sacrifices of Isaiah 57:5 are the murderous fruit of belonging to the father of lies.</p>',
    "6": '<p>"Among the smooth stones of the valley is your portion; they, they are your lot; to them you have poured out a drink offering, you have brought a grain offering. Shall I relent for these things?" The idol-stones that receive sacrifice — the "smooth stones" (<em>ḥalĕqê naḥal</em>) personified as "portion" and "lot" (<em>ḥēleq</em> and <em>gôrāl</em> — the language of YHWH as Israel\'s inheritance, Ps 16:5-6). Choosing stones as one\'s portion instead of YHWH is the paradigm of idolatry: the creature becomes the substitute for the Creator (Rom 1:23: "exchanged the glory of the immortal God for images"). Christ is "the true God and eternal life" (1 John 5:20-21), which immediately precedes "little children, keep yourselves from idols" — the final contrast between the living God in Christ and the stone-lots of Isaiah 57:6.</p>',
    "7": '<p>"On a high and lofty mountain you have set your bed, and there you went up to offer sacrifice." The high-place bed of spiritual adultery — worship at the heights that should be YHWH\'s alone. Rev 17:1-2: the prostitute "is seated on many waters, with whom the kings of the earth have committed sexual immorality." The "high and lofty mountain" (<em>har-gāḇōah wĕniśśāʾ</em>) is the same phrase used of the divine throne in Isa 6:1 and of the Servant\'s exaltation in 52:13 — the idolater installs a counterfeit throne where YHWH\'s throne should be. Rev 2:20: the letter to Thyatira condemns "Jezebel, who calls herself a prophetess and is teaching and seducing my servants to practice sexual immorality" — the same high-place idolatry pattern now occurring within the church.</p>',
    "8": '<p>"Behind the door and the doorpost you have set up your memorial; for, deserting me, you have uncovered your bed, you have gone up to it, you have made it wide; and you have made a covenant for yourself with them, you have loved their bed, you have looked on nakedness." The secret idol behind the door — worship hidden from the covenant Lord. Matt 6:6: "when you pray, go into your room and shut the door and pray to your Father who is in secret" — Jesus transforms the secret room from idolatry\'s hiding place to the place of authentic prayer. The "covenant made with the bed" is the anti-covenant with the idol, the opposite of the new covenant Christ establishes through his blood (Luke 22:20). The deliberate, covenantal nature of the idolatry — not accidental but chosen — is the paradigm of what Christ calls "adultery in the heart" (Matt 5:28).</p>',
    "9": '<p>"You journeyed to the king with oil and multiplied your perfumes; you sent your envoys far off, and sent down even to Sheol." The desperate diplomacy — seeking security in foreign alliances instead of YHWH, going even to the king of death. Heb 2:14-15: "he himself likewise partook of the same things, that through death he might destroy the one who has the power of death, that is, the devil, and deliver all those who through fear of death were subject to lifelong slavery." The "going down to Sheol" to seek a patron describes both the futility of death-negotiations and the depth to which human fear of death drives people. Christ descended to Sheol not in futile diplomacy but in victory (1 Pet 3:19: "he proclaimed to the spirits in prison"; Rev 1:18: "I have the keys of Death and Hades").</p>',
    "10": '<p>"You were wearied with the length of your way, but you did not say, \'It is hopeless\'; you found new life for your strength, and so you were not faint." The stubborn persistence of idolatry despite the exhaustion — not repentance but self-renewal in sin. Rom 1:32: "though they know God\'s righteous decree that those who practice such things deserve to die, they not only do them but give approval to those who practice them." Rev 9:20-21: despite the plagues, the survivors "did not repent of the works of their hands." The contrast with the way of the Servant (42:4: "he will not grow faint or be discouraged") is that the Servant\'s perseverance is toward justice, while the idolater\'s perseverance is toward destruction. The weariness that refuses to say "it is hopeless" — refuses repentance — is the hardened heart that makes sin its identity.</p>',
    "11": '<p>"Whom did you dread and fear, so that you lied and did not remember me, did not lay it to heart? Have I not held my peace, even for a long time, and you do not fear me?" The divine question about the misplaced fear — fearing creatures rather than the Creator. 1 Pet 3:14-15: "do not be afraid of their intimidation, and do not be troubled; but in your hearts honor Christ the Lord as holy." Matt 10:28: "do not fear those who kill the body but cannot kill the soul. Rather fear him who can destroy both soul and body in hell." The long divine silence (v.11b) that allowed the idolaters to imagine YHWH had forgotten mirrors 42:14 — but the silence ends in judgment (42:13-15) or mercy (57:15-19) depending on the response. The failure to "lay it to heart" (<em>śam ʿal-lēb</em>) is the repeated Isaianic indictment (44:19; 47:7) of spiritual stupor.</p>',
    "12": '<p>"I will declare your righteousness and your deeds, but they will not profit you." The ironic divine declaration of the idolater\'s righteousness — a righteousness that profits nothing. Phil 3:8-9: "I count everything as loss because of the surpassing worth of knowing Christ Jesus my Lord... that I may gain Christ and be found in him, not having a righteousness of my own that comes from the law, but that which comes through faith in Christ." The "righteousness" that the idolater can claim — their ritual acts, their sincere devotion to the wrong objects — cannot save them. Rom 10:3: "seeking to establish their own, they did not submit to God\'s righteousness." The contrast: the righteousness that profits nothing (57:12) vs. the righteousness of Christ imputed to those who trust him (2 Cor 5:21).</p>',
    "13": '<p>"When you cry out, let your collection of idols deliver you! The wind will carry them all off, a breath will take them away. But he who takes refuge in me shall possess the land and shall inherit my holy mountain." The ineffectiveness of idols against the coming wind — and the contrasting promise to those who take refuge in YHWH. Matt 7:24-27: the house on rock vs. the house on sand when the wind and flood come. 1 Pet 1:18: "futile ways inherited from your forefathers" — idols as futile inheritance. The "take refuge" (<em>ḥôseh bî</em>) language is the language of the Psalter (Ps 2:12: "blessed are all who take refuge in him"; 5:11; 34:8). John 14:6: "I am the way, the truth, and the life" — Christ is the refuge that idols cannot provide. Rev 21:7: "the one who conquers will have this heritage" — the inheritance of the holy mountain for those who take refuge.</p>',
    "14": '<p>"And it shall be said, \'Build up, build up, prepare the way, remove every obstruction from my people\'s way.\'" The third "prepare the way" passage in Isaiah (after 40:3 and 62:10). Matt 3:3/Mark 1:3/Luke 3:4/John 1:23: all four evangelists identify John the Baptist as the fulfillment of 40:3\'s "prepare the way of the Lord." The triple repetition of the road-clearing command across Isaiah (40:3; 57:14; 62:10) frames the entire central section — the way prepared is the way Christ walks in his incarnation, passion, and parousia. The "obstruction" (<em>mikhšôl</em>, stumbling block) removed is what Paul says Christ is to those who stumble (1 Cor 1:23: "a stumbling block to Jews"), but also what Christ removes for those who receive him — "he is not a stone of stumbling but a cornerstone" for those who believe (1 Pet 2:6-7).</p>',
    "15": '<p>"For thus says the One who is high and lifted up, who inhabits eternity, whose name is Holy: \'I dwell in the high and holy place, and also with him who is of a contrite and lowly spirit, to revive the spirit of the lowly, and to revive the heart of the contrite.\'" The theological summit of Isaiah 57. "High and lifted up" (<em>rām wĕniśśāʾ</em>) = 52:13 (the Servant\'s exaltation) = 6:1 (YHWH\'s throne). John 12:41: "Isaiah said these things because he saw his glory, and he spoke of him" — John identifies these Isaianic visions as visions of Christ. The infinite God who inhabits eternity (<em>šōkēn ʿad</em>) also dwells with the contrite and lowly (<em>dal wĕšĕpal-rûaḥ</em>) — the same divine person simultaneously fills the cosmic throne and the crushed human heart. John 14:23: "we will come to him and make our home with him." Matt 5:3: "Blessed are the poor in spirit, for theirs is the kingdom of heaven." The incarnation is the event in which YHWH who inhabits eternity became the "contrite and lowly" servant of 42:2-3 in order to dwell with the contrite.</p>',
    "16": '<p>"For I will not contend forever, nor will I always be angry; for the spirit would grow faint before me, and the breath of life that I made." The limit on divine judgment — YHWH will not contend forever because to do so would destroy the very creature whose breath he gave. Rom 2:4: "God\'s kindness is meant to lead you to repentance." Lam 3:22-23: "the steadfast love of YHWH never ceases; his mercies never come to an end; they are new every morning." Heb 12:6: "the Lord disciplines the one he loves, and chastises every son whom he receives." The breath of life (<em>nišmat</em>) that YHWH made (Gen 2:7) is his own donation to humanity — he will not permanently destroy what he graciously created. This is the theological ground for the incarnation: the Creator who gave the breath of life enters the creature to revive the spirit that sin has nearly extinguished.</p>',
    "17": '<p>"Because of the iniquity of his unjust gain I was angry; I struck him; I hid my face and was angry, but he went on backsliding in the way of his own heart." The cycle of judgment and persistence in sin. Rom 1:24-28: God "gave them up" — the three-fold divine handing-over in Romans 1, where YHWH lets human rebellion run its self-destructive course. Heb 3:13: "exhort one another every day, as long as it is called \'today,\' that none of you may be hardened by the deceitfulness of sin." The hardening — "he went on backsliding in the way of his own heart" — is the state that Christ came to break: Mark 3:5 (Jesus "grieved at their hardness of heart"); John 12:40 (the hardening of Isaiah 6:9-10 persists into the generation that rejects Christ). The "hidden face" of YHWH in judgment is what Christ experienced on the cross (Matt 27:46: "My God, my God, why have you forsaken me?").</p>',
    "18": '<p>"I have seen his ways, but I will heal him; I will lead him and restore comfort to him and his mourning ones, creating the fruit of the lips." The divine intention to heal despite full knowledge of the ways — the pastoral promise. Mark 2:17: "those who are well have no need of a physician, but those who are sick. I came not to call the righteous, but sinners." Jas 5:15-16: the prayer of faith will save the sick person, and the Lord will raise him up. "Creating the fruit of the lips" (<em>bôrēʾ nîb śĕp̄ātayim</em>) — new speech, new praise — is the transformation the Spirit accomplishes: Acts 2:4 (new tongues at Pentecost); Rom 8:26 (the Spirit intercedes with groans); 1 Cor 14:2 (speaking in tongues). Luke 4:18: "to proclaim liberty to the captives and recovering of sight to the blind, to set at liberty those who are oppressed" — Christ as the physician who heals precisely the "ways" he has seen.</p>',
    "19": '<p>"Peace, peace, to the far and to the near, says YHWH, and I will heal him." The double-peace proclamation with universal scope. Eph 2:17: "he came and preached peace to you who were far off and peace to those who were near" — Paul applies this verse directly to Christ\'s ministry, explicitly identifying "the far" with Gentiles and "the near" with Israel. The "peace, peace" (<em>šālôm šālôm</em>) is the intensified double form of the deepest covenant word. John 20:19,21,26: the risen Christ greets the disciples three times with "Peace be with you" — the post-resurrection announcement that the Servant\'s wounds (53:5: "with his wounds we are healed") have produced the healing of 57:19. Rom 5:1: "since we have been justified by faith, we have peace with God through our Lord Jesus Christ." The far and near healed: the Gentile world and the Jewish people brought into one new humanity (Eph 2:15-16).</p>',
    "20": '<p>"But the wicked are like the tossing sea; for it cannot be quiet, and its waters toss up mire and dirt." The wicked like the restless sea — the image of the unredeemed creation in its churning disorder. Mark 4:37-41: the storm on the Sea of Galilee; Jesus rebukes the wind and says "Peace! Be still!" (<em>phimōthēti</em>, be muzzled) — the tossing sea commanded to quietness that the wicked cannot achieve for themselves. Rev 13:1: the beast rises from the sea — the wicked power emerging from the chaos-waters of 57:20. Rev 21:1: "the sea was no more" — the new creation is defined partly by the absence of the restless, wicked sea. The mire and dirt (<em>rifeš ûmāʾ</em>) that the wicked waters churn up is the pollution of sin — the contrast with the pure river of water of life in Rev 22:1-2 that flows clear from the throne of God and of the Lamb.</p>',
    "21": '<p>"\'There is no peace,\' says my God, \'for the wicked.\'" The motto that closes both chapter 48 (48:22) and this chapter — the structural refrain that runs through Isaiah 40-57. John 14:27: "Peace I leave with you; my peace I give to you. Not as the world gives do I give to you." The peace Christ gives is precisely what the wicked of 57:21 cannot have — not because God withholds it arbitrarily but because their wickedness is the rejection of the only source of peace. Rom 3:17 (citing Isa 59:8): "the way of peace they have not known." Christ is "our peace" (Eph 2:14) — the "no peace for the wicked" is the flip side of "peace through the blood of his cross" (Col 1:20). Those who refuse the Servant\'s suffering bear their own restlessness; those who receive it receive the peace that passes understanding (Phil 4:7).</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    # INTENT: Verify all 21 Isaiah 57 mkt-christ verses present against interlinear
    # CHANGE? If interlinear/isaiah.json ch 57 verse count changes, update expected total
    # VERIFY: Console shows OK with 21 verses; no MISSING output
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'isaiah.json').read_text())
    missing = [v for v in il.get('57', {}) if v not in out.get('57', {})]
    if missing:
        print(f'  MISSING ch 57: {missing}')
    else:
        print(f'  OK: all Isaiah 57 mkt-christ verses present ({len(il.get("57", {}))} verses)')

if __name__ == '__main__':
    main()
